1	use chrono::NaiveDateTime;
2	use hmac::{Hmac, Mac};
3	use rand::Rng;
4	use sha2::Sha256;
5	
6	type HmacSha256 = Hmac<Sha256>;
7	
8	/// Configuration for cookie-based session management.
9	pub struct SessionConfig {
10	    pub cookie_secret: [u8; 32],
11	    /// Idle timeout in seconds (default 1800 = 30 min).
12	    pub idle_timeout_secs: u64,
13	    /// How often session IDs are rotated (default 300 = 5 min).
14	    pub rotation_interval_secs: u64,
15	}
16	
17	impl SessionConfig {
18	    /// Build from the `COOKIE_SECRET` env var (or a default dev secret).
19	    /// The raw value is hashed with SHA-256 to produce a 32-byte key.
20	    pub fn from_env() -> Self {
21	        let raw = std::env::var("COOKIE_SECRET")
22	            .unwrap_or_else(|_| "brewflow-dev-cookie-secret".into());
23	
24	        use sha2::Digest;
25	        let mut hasher = sha2::Sha256::new();
26	        hasher.update(raw.as_bytes());
27	        let hash: [u8; 32] = hasher.finalize().into();
28	
29	        SessionConfig {
30	            cookie_secret: hash,
31	            idle_timeout_secs: 1800,
32	            rotation_interval_secs: 300,
33	        }
34	    }
35	}
36	
37	/// Generate a cryptographically-random 32-byte hex session ID.
38	pub fn create_session_id() -> String {
39	    let mut bytes = [0u8; 32];
40	    rand::thread_rng().fill(&mut bytes);
41	    hex::encode(bytes)
42	}
43	
44	/// Sign a session ID with HMAC-SHA256 and return `session_id.signature`.
45	pub fn sign_cookie(config: &SessionConfig, session_id: &str) -> String {
46	    let mut mac =
47	        HmacSha256::new_from_slice(&config.cookie_secret).expect("HMAC accepts any key length");
48	    mac.update(session_id.as_bytes());
49	    let signature = hex::encode(mac.finalize().into_bytes());
50	    format!("{}.{}", session_id, signature)
51	}
52	
53	/// Verify a signed cookie value (`session_id.signature`).
54	/// Returns the session_id if the HMAC is valid, `None` otherwise.
55	pub fn verify_cookie(config: &SessionConfig, cookie_value: &str) -> Option<String> {
56	    let (session_id, signature) = cookie_value.rsplit_once('.')?;
57	    let sig_bytes = hex::decode(signature).ok()?;
58	
59	    let mut mac =
60	        HmacSha256::new_from_slice(&config.cookie_secret).expect("HMAC accepts any key length");
61	    mac.update(session_id.as_bytes());
62	    mac.verify_slice(&sig_bytes).ok()?;
63	
64	    Some(session_id.to_string())
65	}
66	
67	/// Returns `true` if the session should be rotated (i.e. `last_rotated` is
68	/// older than `rotation_interval_secs`).
69	pub fn should_rotate(last_rotated: NaiveDateTime, config: &SessionConfig) -> bool {
70	    let now = chrono::Utc::now().naive_utc();
71	    let elapsed = now.signed_duration_since(last_rotated);
72	    elapsed.num_seconds() as u64 >= config.rotation_interval_secs
73	}
74	
75	#[cfg(test)]
76	mod tests {
77	    use super::*;
78	
79	    fn test_config() -> SessionConfig {
80	        SessionConfig {
81	            cookie_secret: [42u8; 32],
82	            idle_timeout_secs: 1800,
83	            rotation_interval_secs: 300,
84	        }
85	    }
86	
87	    #[test]
88	    fn sign_then_verify_round_trip() {
89	        let config = test_config();
90	        let session_id = "deadbeef1234567890abcdef";
91	        let signed = sign_cookie(&config, session_id);
92	        let recovered = verify_cookie(&config, &signed);
93	        assert_eq!(recovered, Some(session_id.to_string()));
94	    }
95	
96	    #[test]
97	    fn verify_tampered_signature_fails() {
98	        let config = test_config();
