120	pub struct StaffGuard {
121	    pub claims: Claims,
122	}
123	
124	#[rocket::async_trait]
125	impl<'r> FromRequest<'r> for StaffGuard {
126	    type Error = &'static str;
127	
128	    async fn from_request(request: &'r Request<'_>) -> Outcome<Self, Self::Error> {
129	        let user = match AuthenticatedUser::from_request(request).await {
130	            Outcome::Success(u) => u,
131	            Outcome::Error(e) => return Outcome::Error(e),
132	            Outcome::Forward(f) => return Outcome::Forward(f),
133	        };
134	
135	        if user.claims.roles.iter().any(|r| r == "Staff" || r == "Admin") {
136	            Outcome::Success(StaffGuard { claims: user.claims })
137	        } else {
138	            Outcome::Error((Status::Forbidden, "Staff or Admin role required"))
139	        }
140	    }
141	}
