15	// ---------------------------------------------------------------------------
16	// Helper: verify a cart item belongs to the authenticated user's cart
17	// ---------------------------------------------------------------------------
18	async fn verify_cart_item_ownership(pool: &MySqlPool, item_id: i64, user_id: i64) -> bool {
19	    let cart_id = crate::db::cart::get_or_create_cart(pool, user_id).await.unwrap_or(-1);
20	    sqlx::query_scalar::<_, i64>("SELECT COUNT(*) FROM cart_items WHERE id = ? AND cart_id = ?")
21	        .bind(item_id)
22	        .bind(cart_id)
23	        .fetch_one(pool)
24	        .await
25	        .unwrap_or(0)
26	        > 0
27	}
