29	// ---------------------------------------------------------------------------
30	// Helper: build a CartResponse from the DB cart items
31	// ---------------------------------------------------------------------------
32	async fn build_cart_response(pool: &MySqlPool, user_id: i64) -> Result<CartResponse, String> {
33	    let cart_id = crate::db::cart::get_or_create_cart(pool, user_id)
34	        .await
35	        .map_err(|e| format!("Failed to get cart: {}", e))?;
36	
37	    let rows = crate::db::cart::get_cart_items(pool, cart_id).await;
38	
39	    let tax_config = crate::db::store::get_tax_config(pool).await;
40	    let tax_rate = tax_config.map(|t| t.rate).unwrap_or(0.0);
41	
42	    let items: Vec<CartItemDetail> = rows
43	        .iter()
44	        .map(|r| CartItemDetail {
45	            id: r.id,
46	            spu_name_en: r.spu_name_en.clone(),
47	            spu_name_zh: r.spu_name_zh.clone(),
48	            sku_code: Some(r.sku_code.clone()),
49	            options: r.option_labels.clone(),
50	            quantity: r.quantity,
51	            unit_price: r.unit_price,
52	            line_total: r.unit_price * r.quantity as f64,
53	        })
54	        .collect();
55	
56	    let subtotal: f64 = items.iter().map(|i| i.line_total).sum();
57	    let tax_amount = crate::services::pricing::calculate_tax(subtotal, tax_rate);
58	    let total = crate::services::pricing::calculate_total(subtotal, tax_amount);
59	
60	    Ok(CartResponse {
61	        items,
62	        subtotal,
63	        tax_rate,
64	        tax_amount,
65	        total,
66	    })
67	}
