98	#[post("/add", data = "<body>")]
99	pub async fn add_to_cart(
100	    pool: &State<MySqlPool>,
101	    user: AuthenticatedUser,
102	    body: Json<AddToCartRequest>,
103	) -> Result<Json<ApiResponse<CartResponse>>, (Status, Json<ApiResponse<()>>)> {
104	    let user_id = user.claims.sub;
105	
106	    // Validate quantity
107	    if body.quantity < 1 {
108	        return Err((
109	            Status::UnprocessableEntity,
110	            Json(ApiResponse {
111	                success: false,
112	                data: None,
113	                error: Some("Quantity must be at least 1".into()),
114	            }),
115	        ));
116	    }
117	
118	    // Look up the SPU to get base price
119	    let spu = crate::db::products::get_spu(pool.inner(), body.spu_id)
120	        .await
121	        .ok_or_else(|| {
122	            (
123	                Status::NotFound,
124	                Json(ApiResponse {
125	                    success: false,
126	                    data: None,
127	                    error: Some("Product not found".into()),
128	                }),
129	            )
130	        })?;
131	
132	    // Validate that all submitted option_value_ids belong to this SPU.
133	    // This prevents a client from mixing options from different products.
134	    for ov_id in &body.selected_options {
135	        let ov = crate::db::products::get_option_value_by_id(pool.inner(), *ov_id).await;
136	        let belongs = match ov {
137	            Some(ref v) => {
138	                // Resolve the option_group → SPU linkage: option_group.spu_id must match
139	                crate::db::products::option_value_belongs_to_spu(pool.inner(), v.id, body.spu_id).await
140	            }
141	            None => false,
142	        };
143	        if !belongs {
144	            return Err((
145	                Status::UnprocessableEntity,
146	                Json(ApiResponse {
147	                    success: false,
148	                    data: None,
149	                    error: Some(format!("Option value {} does not belong to this product", ov_id)),
150	                }),
151	            ));
152	        }
153	    }
154	
155	    // Enforce required option groups: every group with is_required=true must have
156	    // at least one of its option_value_ids present in the submitted selection.
157	    let option_groups = crate::db::products::get_option_groups(pool.inner(), body.spu_id).await;
158	    for group in option_groups.iter().filter(|g| g.is_required) {
159	        let group_values = crate::db::products::get_option_values(pool.inner(), group.id).await;
160	        let group_value_ids: std::collections::HashSet<i64> =
161	            group_values.into_iter().map(|v| v.id).collect();
162	        let has_selection = body.selected_options.iter().any(|id| group_value_ids.contains(id));
163	        if !has_selection {
164	            return Err((
165	                Status::UnprocessableEntity,
166	                Json(ApiResponse {
167	                    success: false,
168	                    data: None,
169	                    error: Some(format!(
170	                        "Required option group '{}' has no selection",
171	                        group.name_en
172	                    )),
173	                }),
174	            ));
175	        }
176	    }
177	
178	    // Calculate unit price: base price + sum of option deltas
179	    let mut option_delta = 0.0_f64;
180	    for ov_id in &body.selected_options {
181	        if let Some(ov) = crate::db::products::get_option_value_by_id(pool.inner(), *ov_id).await {
182	            option_delta += ov.price_delta;
183	        }
184	    }
185	
186	    // Try to find a matching SKU
187	    let sku = crate::db::products::get_sku_by_options(pool.inner(), body.spu_id, &body.selected_options).await;
188	    let unit_price = if let Some(ref s) = sku {
189	        s.price
190	    } else {
191	        spu.base_price + option_delta
192	    };
193	
194	    let sku_id = match sku.map(|s| s.id).or(body.sku_id) {
195	        Some(id) if id > 0 => id,
196	        _ => return Err((
197	            Status::UnprocessableEntity,
198	            Json(ApiResponse {
199	                success: false,
200	                data: None,
201	                error: Some("No valid SKU found for the given product and options".into()),
202	            }),
203	        )),
204	    };
205	
206	    let cart_id = crate::db::cart::get_or_create_cart(pool.inner(), user_id)
207	        .await
208	        .map_err(|_| {
209	            (
210	                Status::InternalServerError,
211	                Json(ApiResponse {
212	                    success: false,
213	                    data: None,
214	                    error: Some("Failed to get or create cart".into()),
215	                }),
216	            )
217	        })?;
218	
219	    let cart_item_id = crate::db::cart::add_item(pool.inner(), cart_id, sku_id, body.quantity, unit_price)
220	        .await
221	        .map_err(|_| {
222	            (
223	                Status::InternalServerError,
224	                Json(ApiResponse {
225	                    success: false,
226	                    data: None,
227	                    error: Some("Failed to add item to cart".into()),
228	                }),
229	            )
230	        })?;
231	
232	    if !body.selected_options.is_empty() {
233	        let _ = crate::db::cart::add_item_options(pool.inner(), cart_item_id, &body.selected_options).await;
234	    }
235	
236	    let cart = build_cart_response(pool.inner(), user_id)
237	        .await
238	        .map_err(|e| {
239	            (
240	                Status::InternalServerError,
241	                Json(ApiResponse {
242	                    success: false,
243	                    data: None,
244	                    error: Some(e),
245	                }),
246	            )
247	        })?;
248	
249	    Ok(Json(ApiResponse {
250	        success: true,
251	        data: Some(cart),
252	        error: None,
253	    }))
254	}
