111	        let body: serde_json::Value =
112	            serde_json::from_str(&resp.into_string().unwrap_or_default())
113	                .expect("login response must be valid JSON");
114	        let cookie = body["data"]["session_cookie"]
115	            .as_str()
116	            .expect("session_cookie must be present")
117	            .to_string();
118	        assert!(!cookie.is_empty(), "session_cookie must not be empty");
