122	    // ── Macro: require DB — panics if TEST_DATABASE_URL is absent ───────────
123	
124	    /// Builds a `db_rocket()` or panics.
125	    ///
126	    /// DB-dependent tests MUST fail loudly when `TEST_DATABASE_URL` is not set.
127	    /// Use `cargo test` filters or `run_tests.sh` to exclude them locally.
128	    /// Returns `(runtime, rocket)`.  The runtime **must** stay alive for the
129	    /// entire test because the sqlx pool spawns background tasks on it.
130	    /// Bind it as `_rt` so the drop runs at the end of the test function.
131	    macro_rules! require_db {
132	        () => {{
133	            let rt = tokio::runtime::Runtime::new().unwrap();
134	            let rocket = rt.block_on(db_rocket()).expect(
135	                "TEST_DATABASE_URL (or DATABASE_URL) must be set and connectable to run DB tests.\n\
136	                 To skip DB tests locally: cargo test --package backend -- --skip login --skip customer --skip add_to_cart --skip confirm_order --skip scan_voucher"
137	            );
138	            (rt, rocket)
139	        }};
140	    }
