21	/// Fetch option_value_ids for a single cart item.
22	async fn get_cart_item_option_ids(pool: &MySqlPool, cart_item_id: i64) -> Vec<i64> {
23	    let rows = sqlx::query_scalar::<_, i64>(
24	        "SELECT option_value_id FROM cart_item_options WHERE cart_item_id = ? ORDER BY option_value_id",
