260	#[get("/")]
261	pub async fn list_orders(
262	    pool: &State<MySqlPool>,
263	    crypto: &State<CryptoConfig>,
264	    user: AuthenticatedUser,
265	) -> Json<ApiResponse<Vec<OrderSummary>>> {
266	    let orders = crate::db::orders::get_user_orders(pool.inner(), user.claims.sub).await;
267	
268	    let mut summaries: Vec<OrderSummary> = Vec::with_capacity(orders.len());
269	    for o in orders {
270	        let (voucher_code, pickup_slot) = if let Some(res_id) = o.reservation_id {
271	            match crate::db::store::get_reservation(pool.inner(), res_id).await {
272	                Some(r) => {
273	                    let slot = format!(
274	                        "{} - {}",
275	                        r.pickup_slot_start.format("%Y-%m-%dT%H:%M:%S"),
276	                        r.pickup_slot_end.format("%Y-%m-%dT%H:%M:%S"),
277	                    );
278	                    // reservations.voucher_code is now a SHA-256 hash; recover the
279	                    // display value by decrypting from the vouchers table.
280	                    let display_code = crate::db::store::get_encrypted_code_by_reservation_id(
281	                        pool.inner(), res_id,
282	                    )
283	                    .await
284	                    .and_then(|enc| crate::services::crypto::decrypt(crypto.inner(), &enc).ok());
285	                    if let Some(ref vc) = display_code {
286	                        tracing::info!(
287	                            order_id = o.id,
288	                            voucher = %crate::services::crypto::mask_for_log(vc, 4),
289	                            "Order listed with voucher"
290	                        );
291	                    }
292	                    (display_code, Some(slot))
293	                }
294	                None => (None, None),
295	            }
296	        } else {
297	            (None, None)
298	        };
299	
300	        summaries.push(OrderSummary {
301	            id: o.id,
302	            order_number: o.order_number,
303	            status: o.status,
304	            total: o.total,
305	            voucher_code,
306	            created_at: o.created_at.format("%Y-%m-%dT%H:%M:%S").to_string(),
307	            pickup_slot,
308	        });
309	    }
310	
311	    Json(ApiResponse {
312	        success: true,
313	        data: Some(summaries),
314	        error: None,
315	    })
316	}
