320	    pool: &State<MySqlPool>,
321	    crypto: &State<CryptoConfig>,
322	    user: AuthenticatedUser,
323	    id: i64,
324	) -> Result<Json<ApiResponse<OrderDetail>>, (Status, Json<ApiResponse<()>>)> {
325	    let order = crate::db::orders::get_order(pool.inner(), id)
326	        .await
327	        .ok_or_else(|| {
328	            (
329	                Status::NotFound,
330	                Json(ApiResponse {
331	                    success: false,
332	                    data: None,
333	                    error: Some("Order not found".into()),
334	                }),
335	            )
336	        })?;
337	
338	    // Verify the order belongs to this user
339	    if order.user_id != user.claims.sub {
340	        return Err((
341	            Status::Forbidden,
342	            Json(ApiResponse {
343	                success: false,
344	                data: None,
345	                error: Some("Order does not belong to you".into()),
346	            }),
347	        ));
348	    }
349	
350	    let items_rows = crate::db::orders::get_order_items(pool.inner(), order.id).await;
351	    let items: Vec<OrderItemDetail> = items_rows
352	        .into_iter()
353	        .map(|i| OrderItemDetail {
354	            sku_code: i.sku_code,
355	            spu_name: i.spu_name,
356	            options: i.options,
357	            quantity: i.quantity,
358	            unit_price: i.unit_price,
359	            item_total: i.item_total,
360	        })
361	        .collect();
362	
363	    let events = crate::db::orders::get_fulfillment_events(pool.inner(), order.id).await;
364	    let fulfillment_history: Vec<FulfillmentEventDetail> = events
365	        .into_iter()
366	        .map(|e| FulfillmentEventDetail {
367	            from_status: e.from_status,
368	            to_status: e.to_status,
369	            changed_by: e.changed_by_user_id.to_string(),
370	            notes: e.notes,
371	            timestamp: e.created_at.format("%Y-%m-%dT%H:%M:%S").to_string(),
372	        })
373	        .collect();
374	
375	    // Get reservation if present; decrypt the voucher code for display.
376	    let reservation = if let Some(res_id) = order.reservation_id {
377	        match crate::db::store::get_reservation(pool.inner(), res_id).await {
378	            Some(r) => {
379	                let display_code = crate::db::store::get_encrypted_code_by_reservation_id(
380	                    pool.inner(), res_id,
381	                )
382	                .await
383	                .and_then(|enc| crate::services::crypto::decrypt(crypto.inner(), &enc).ok())
384	                .unwrap_or_default();
385	                if !display_code.is_empty() {
386	                    tracing::info!(
387	                        order_id = order.id,
388	                        voucher = %crate::services::crypto::mask_for_log(&display_code, 4),
389	                        "Order detail viewed with voucher"
390	                    );
391	                }
392	                Some(ReservationDetail {
393	                    voucher_code: display_code,
394	                    pickup_slot_start: r.pickup_slot_start.format("%Y-%m-%dT%H:%M:%S").to_string(),
395	                    pickup_slot_end: r.pickup_slot_end.format("%Y-%m-%dT%H:%M:%S").to_string(),
396	                    hold_expires_at: r.hold_expires_at.format("%Y-%m-%dT%H:%M:%S").to_string(),
397	                    status: r.status,
398	                })
399	            }
400	            None => None,
401	        }
402	    } else {
403	        None
404	    };
405	
406	    let (vc, ps) = if let Some(ref res) = reservation {
407	        (
408	            Some(res.voucher_code.clone()),
409	            Some(format!("{} - {}", res.pickup_slot_start, res.pickup_slot_end)),
410	        )
411	    } else {
412	        (None, None)
413	    };
414	
415	    let summary = OrderSummary {
416	        id: order.id,
417	        order_number: order.order_number,
418	        status: order.status,
419	        total: order.total,
420	        voucher_code: vc,
421	        created_at: order.created_at.format("%Y-%m-%dT%H:%M:%S").to_string(),
422	        pickup_slot: ps,
423	    };
424	
425	    Ok(Json(ApiResponse {
426	        success: true,
427	        data: Some(OrderDetail {
428	            order: summary,
429	            items,
430	            fulfillment_history,
431	            reservation,
432	        }),
433	        error: None,
434	    }))
435	}
