3	/// Full price breakdown for an order.
4	#[derive(Debug, Clone, Serialize, Deserialize)]
5	pub struct PriceBreakdown {
6	    pub subtotal: f64,
7	    pub tax_rate: f64,
8	    pub tax_amount: f64,
9	    pub total: f64,
10	}
11	
12	/// Calculate the price for a single item: base price + sum of option price deltas.
13	pub fn calculate_item_price(base_price: f64, option_deltas: &[f64]) -> f64 {
14	    base_price + option_deltas.iter().sum::<f64>()
15	}
16	
17	/// Calculate the subtotal: sum of (unit_price * quantity) for each item.
18	pub fn calculate_subtotal(items: &[(f64, i32)]) -> f64 {
19	    items.iter().map(|(price, qty)| price * (*qty as f64)).sum()
20	}
21	
22	/// Calculate tax on a subtotal.
23	pub fn calculate_tax(subtotal: f64, tax_rate: f64) -> f64 {
24	    (subtotal * tax_rate * 100.0).round() / 100.0
25	}
26	
27	/// Calculate the final total.
28	pub fn calculate_total(subtotal: f64, tax: f64) -> f64 {
29	    ((subtotal + tax) * 100.0).round() / 100.0
30	}
31	
32	/// Compute a full price breakdown from line items and a tax rate.
33	pub fn compute_breakdown(items: &[(f64, i32)], tax_rate: f64) -> PriceBreakdown {
34	    let subtotal = calculate_subtotal(items);
35	    let tax_amount = calculate_tax(subtotal, tax_rate);
36	    let total = calculate_total(subtotal, tax_amount);
37	
38	    PriceBreakdown {
39	        subtotal,
40	        tax_rate,
41	        tax_amount,
42	        total,
43	    }
44	}
