8	use std::sync::Arc;
9	use rocket_cors::{AllowedOrigins, CorsOptions};
10	
11	#[rocket::launch]
12	async fn rocket() -> _ {
13	    // Initialise tracing subscriber for structured logging.
14	    tracing_subscriber::fmt::init();
15	
16	    let database_url =
17	        std::env::var("DATABASE_URL").unwrap_or_else(|_| "mysql://root:root@localhost/brewflow".into());
18	
19	    let pool = sqlx::MySqlPool::connect(&database_url)
20	        .await
21	        .expect("Failed to connect to MySQL");
22	
23	    // CORS: restrict to origins configured via ALLOWED_ORIGINS (comma-separated).
24	    // Falls back to localhost:8080 in development.  Set ALLOWED_ORIGINS= (empty)
25	    // to disallow all cross-origin requests in strict intranet deployments.
26	    let allowed_origins = {
27	        let raw = std::env::var("ALLOWED_ORIGINS")
28	            .unwrap_or_else(|_| "http://localhost:8080".into());
29	        if raw.is_empty() {
30	            AllowedOrigins::some_exact(&[] as &[&str])
31	        } else {
32	            let origins: Vec<String> = raw.split(',').map(|s| s.trim().to_owned()).collect();
33	            AllowedOrigins::some_exact(&origins)
34	        }
35	    };
36	    let cors = CorsOptions {
37	        allowed_origins,
38	        allow_credentials: true,
39	        ..Default::default()
40	    }
41	    .to_cors()
42	    .expect("CORS config error");
43	
44	    // Session config
45	    let session_config = services::session::SessionConfig::from_env();
46	    let idle_timeout = session_config.idle_timeout_secs;
47	
48	    // Crypto config
49	    let crypto_config = services::crypto::CryptoConfig::from_env();
50	
51	    // Reservation lock manager
52	    let lock_manager = services::reservation_lock::ReservationLockManager::new();
53	
54	    // Degradation manager
55	    let degradation = Arc::new(services::resilience::DegradationManager::new());
56	
57	    // Background job manager
58	    let job_mgr = Arc::new(services::resilience::BackgroundJobManager::new(degradation.clone()));
59	
60	    // Register background jobs
61	    {
62	        let jm = job_mgr.clone();
63	        tokio::spawn(async move {
64	            jm.register_job("session_cleanup", 300, true, 10).await;
65	            jm.register_job("reservation_expiry", 60, true, 10).await;
66	            jm.register_job("offer_expiry", 15, false, 20).await;
67	            jm.register_job("analytics_snapshot", 3600, false, 5).await;
68	            jm.register_job("lock_cleanup", 60, true, 10).await;
69	        });
70	    }
71	
72	    // App start time for uptime tracking
73	    let start_time = routes::health::AppStartTime(chrono::Utc::now().naive_utc());
74	
75	    // -----------------------------------------------------------------------
76	    // Background master loop
77	    // -----------------------------------------------------------------------
78	    {
79	        let bg_pool = pool.clone();
80	        let bg_lock_mgr = lock_manager.clone();
81	        let bg_job_mgr = job_mgr.clone();
82	        let bg_degradation = degradation.clone();
83	        let bg_idle_timeout = idle_timeout;
84	
85	        tokio::spawn(async move {
86	            let mut interval = tokio::time::interval(std::time::Duration::from_secs(10));
87	            loop {
88	                interval.tick().await;
89	
90	                let due = bg_job_mgr.get_due_jobs().await;
91	                for job_name in due {
92	                    match job_name.as_str() {
93	                        "session_cleanup" => {
94	                            match db::sessions::cleanup_expired_sessions(&bg_pool, bg_idle_timeout).await {
95	                                Ok(n) => {
96	                                    if n > 0 { tracing::info!(deleted = n, "cleaned up expired sessions"); }
97	                                    bg_job_mgr.record_job_success("session_cleanup").await;
98	                                    bg_degradation.record_success("sessions").await;
99	                                }
100	                                Err(e) => {
101	                                    bg_job_mgr.record_job_failure("session_cleanup", &e.to_string()).await;
102	                                }
103	                            }
104	                        }
105	                        "reservation_expiry" => {
106	                            match db::store::expire_stale_reservations(&bg_pool).await {
107	                                Ok(n) => {
108	                                    if n > 0 { tracing::info!(expired = n, "expired stale reservations"); }
109	                                    bg_job_mgr.record_job_success("reservation_expiry").await;
110	                                    bg_degradation.record_success("reservations").await;
111	                                }
112	                                Err(e) => {
113	                                    bg_job_mgr.record_job_failure("reservation_expiry", &e.to_string()).await;
114	                                }
115	                            }
116	                        }
117	                        "offer_expiry" => {
118	                            match db::dispatch::expire_stale_offers(&bg_pool).await {
119	                                Ok(n) => {
120	                                    if n > 0 { tracing::info!(expired = n, "expired stale task offers"); }
121	                                    bg_job_mgr.record_job_success("offer_expiry").await;
122	                                }
123	                                Err(e) => {
124	                                    bg_job_mgr.record_job_failure("offer_expiry", &e.to_string()).await;
125	                                }
126	                            }
127	                        }
128	                        "lock_cleanup" => {
129	                            let released = services::reservation_lock::release_expired(
130	                                &bg_pool,
131	                                &bg_lock_mgr,
132	                            )
133	                            .await;
134	                            if !released.is_empty() {
135	                                tracing::info!(count = released.len(), "released expired reservation locks");
136	                            }
137	                            bg_job_mgr.record_job_success("lock_cleanup").await;
138	                            bg_degradation.record_success("reservations").await;
139	                        }
140	                        "analytics_snapshot" => {
141	                            // Placeholder - analytics snapshot job
142	                            bg_job_mgr.record_job_success("analytics_snapshot").await;
143	                            bg_degradation.record_success("analytics").await;
144	                        }
145	                        _ => {}
146	                    }
147	                }
148	            }
149	        });
150	    }
151	
152	    rocket::build()
153	        .manage(pool)
154	        .manage(job_mgr)
155	        .manage(session_config)
156	        .manage(crypto_config)
157	        .manage(lock_manager)
158	        .manage(degradation)
159	        .manage(start_time)
160	        .attach(cors)
161	        .attach(middleware::log_mask::LogMaskFairing)
162	        .mount("/api/auth", routes::auth::routes())
163	        .mount("/api/products", routes::products::routes())
164	        .mount("/api/cart", routes::cart::routes())
165	        .mount("/api/orders", routes::orders::routes())
166	        .mount("/api/staff", routes::staff::routes())
167	        .mount("/api/store", routes::store::routes())
168	        .mount("/api/exam", routes::exam::routes())
169	        .mount("/api/training", routes::training::routes())
170	        .mount("/api/admin", routes::admin::routes())
171	        .mount("/api/i18n", routes::i18n::routes())
172	        .mount("/api/dispatch", routes::dispatch::routes())
173	        .mount("/health", routes::health::routes())
174	        .mount("/", routes::sitemap::routes())
175	}
