18	/// Basic health check – returns 200 if the DB is reachable, 503 otherwise.
19	#[get("/")]
20	pub async fn health(pool: &State<MySqlPool>) -> Result<Json<ApiResponse<String>>, (Status, Json<ApiResponse<()>>)> {
21	    let db = crate::services::health::check_database(pool.inner()).await;
22	    if db.status == "healthy" {
23	        Ok(Json(ApiResponse {
24	            success: true,
25	            data: Some("ok".into()),
26	            error: None,
27	        }))
28	    } else {
29	        Err((
30	            Status::ServiceUnavailable,
31	            Json(ApiResponse {
32	                success: false,
33	                data: None,
34	                error: Some(db.details.unwrap_or_else(|| "Database unreachable".into())),
35	            }),
36	        ))
37	    }
38	}
