40	/// Detailed health report (admin only).
41	#[get("/detailed")]
42	pub async fn detailed(
43	    pool: &State<MySqlPool>,
44	    degradation: &State<std::sync::Arc<DegradationManager>>,
45	    job_mgr: &State<std::sync::Arc<BackgroundJobManager>>,
46	    start: &State<AppStartTime>,
47	    _admin: AdminGuard,
48	) -> Json<crate::services::health::HealthReport> {
49	    let jobs = job_mgr.get_job_statuses().await;
50	    let report = crate::services::health::full_health_check(
51	        pool.inner(),
52	        degradation.inner(),
53	        start.0,
54	        jobs,
55	    )
56	    .await;
57	    Json(report)
58	}
