60	/// Readiness probe – 200 when all critical services are operational.
61	#[get("/ready")]
62	pub async fn ready(
63	    pool: &State<MySqlPool>,
64	    degradation: &State<std::sync::Arc<DegradationManager>>,
65	) -> Result<Json<ApiResponse<String>>, (Status, Json<ApiResponse<()>>)> {
66	    let db = crate::services::health::check_database(pool.inner()).await;
67	    if db.status != "healthy" {
68	        return Err((
69	            Status::ServiceUnavailable,
70	            Json(ApiResponse { success: false, data: None, error: Some("Database unavailable".into()) }),
71	        ));
72	    }
73	
74	    let statuses = degradation.get_status().await;
75	    let critical_degraded: Vec<_> = statuses
76	        .iter()
77	        .filter(|(_, v)| v.is_critical && v.is_degraded)
78	        .map(|(k, _)| k.clone())
79	        .collect();
80	
81	    if critical_degraded.is_empty() {
82	        Ok(Json(ApiResponse { success: true, data: Some("ready".into()), error: None }))
83	    } else {
84	        Err((
85	            Status::ServiceUnavailable,
86	            Json(ApiResponse {
87	                success: false,
88	                data: None,
89	                error: Some(format!("Critical services degraded: {}", critical_degraded.join(", "))),
90	            }),
91	        ))
92	    }
93	}
